#include<bits/stdc++.h>
using namespace std;
const int MAXN=2e+5;
int a[MAXN],cf[MAXN],n;
long long x[MAXN],y[MAXN];
int main(void){
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i],cf[i]=a[i]-a[i-1];
    for(int i=2,j=n;i<=n;i++,j--)x[i]=(cf[i]<=0?x[i-1]-(cf[i]-1):x[i-1]),y[j]=(cf[j]>=0?y[j+1]+(cf[j]+1):y[j+1]);
    long long ans=LONG_LONG_MAX;
    for(int i=1;i<=n;i++)ans=min(ans,max(x[i],y[i+1]));
    cout<<ans;
    return false;
}
